// Handle Places API (New) response format
const places = $json.places || [];
const city = $('Texas Zip Codes').item.json.city;
const zip = $('Texas Zip Codes').item.json.zip;
const region = $('Texas Zip Codes').item.json.region;

if (places.length === 0) {
  return [];
}

return places.map(place => ({
  json: {
    place_id: place.id || '',
    name: place.displayName?.text || '',
    address: place.formattedAddress || '',
    phone_number: place.nationalPhoneNumber || '',
    website: place.websiteUri || '',
    rating: place.rating || '',
    review_count: place.userRatingCount || 0,
    city: city,
    zip: zip,
    region: region,
    status: 'New',
    scraped_at: new Date().toISOString().split('T')[0]
  }
}));
